// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PresaleMint {
    address private immutable owner;
    enum State { PresaleLive, SaleLive, SaleClosed }
    State public currentState = State.PresaleLive;

    mapping(address => bool) public presalerList;
    uint256 public presaleAmountMinted;
    uint256 public publicAmountMinted;

    event ToggleSale(State newState);
    event WhitelistChanged(address indexed user, bool status);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    function toggleSale() public onlyOwner {
        if (currentState == State.PresaleLive) {
            currentState = State.SaleLive;
        } else if (currentState == State.SaleLive) {
            currentState = State.SaleClosed;
        } else if (currentState == State.SaleClosed) {
            currentState = State.PresaleLive;
        } else {
            revert("Invalid current state");
        }
        emit ToggleSale(currentState);
    }

    function whitelist(address user, bool status) public onlyOwner {
        presalerList[user] = status;
        emit WhitelistChanged(user, status);
    }

    function presaleBuy() public payable {
        require(currentState == State.PresaleLive, "Presale is not live");
        require(presalerList[msg.sender], "Not whitelisted");
        presaleAmountMinted++;
    }

    function buy() public payable {
        require(currentState == State.SaleLive, "Sale is not live");
        publicAmountMinted++;
    }
}
